import { NextResponse } from "next/server";
export async function POST(req){const b=await req.json();const key=process.env.GOOGLE_MAPS_API_KEY;const q=b.query||"event vendors";const lat=b.lat||38.4221;const lng=b.lng||-77.4083;if(!key)return NextResponse.json({ok:false,mode:"placeholder",message:"Add GOOGLE_MAPS_API_KEY to enable real nearby vendor search.",results:[{name:"Elite Sound DJs",category:"DJ / Music",location:"Stafford, VA",price:"$350 - $900",rating:4.9,lat:38.4221,lng:-77.4083,verified:true},{name:"Fresh Flame Catering",category:"Catering",location:"Fredericksburg, VA",price:"$15 - $45/guest",rating:4.8,lat:38.3032,lng:-77.4605,verified:true}]});const url=`https://maps.googleapis.com/maps/api/place/textsearch/json?query=${encodeURIComponent(q)}&location=${lat},${lng}&radius=50000&key=${key}`;const r=await fetch(url);const data=await r.json();const results=(data.results||[]).slice(0,12).map(p=>({name:p.name,category:q,location:p.formatted_address||"Nearby",price:"Contact for pricing",rating:p.rating||"N/A",lat:p.geometry?.location?.lat,lng:p.geometry?.location?.lng,verified:false,place_id:p.place_id}));return NextResponse.json({ok:true,message:"Nearby vendor search complete.",results});}